const inp = $input.first().json;

const validTypes = ['Decision', 'Learning', 'Error', 'Insight', 'Pattern', 'Fact', 'Drift'];
const validProjects = ['TJ', 'TM', 'CL', 'CF', 'Ops', 'Personal'];

if (!inp.summary || !inp.details) {
  throw new Error('summary and details required');
}
if (!validTypes.includes(inp.type)) {
  throw new Error(`Invalid type: ${inp.type}. Must be one of: ${validTypes.join(', ')}`);
}
if (!validProjects.includes(inp.project)) {
  throw new Error(`Invalid project: ${inp.project}. Must be one of: ${validProjects.join(', ')}`);
}

const importance = parseInt(inp.importance);
if (isNaN(importance) || importance < 1 || importance > 5) {
  throw new Error('importance must be integer 1-5');
}

let tags = inp.tags;
if (typeof tags === 'string') {
  try {
    tags = JSON.parse(tags);
  } catch(e) {
    tags = [tags];
  }
}
if (!Array.isArray(tags)) {
  tags = [];
}
tags = tags.filter(t => t && typeof t === 'string').map(t => t.trim()).filter(Boolean);

return [{
  json: {
    summary: String(inp.summary).trim(),
    details: String(inp.details).trim(),
    source: String(inp.source).trim(),
    type: inp.type,
    project: inp.project,
    importance: importance,
    tags: tags
  }
}];

const result = $input.first().json;
const upstream = $('Validate Input').item.json;

const row = Array.isArray(result) ? result[0] : result;

return [{
  json: {
    success: true,
    id: row?.id || null,
    summary: upstream.summary,
    project: upstream.project,
    source: upstream.source,
    tags_count: upstream.tags.length
  }
}];
